class Solution:
    def processStr(self, s):
        res = ''
        for ch in s:
            if ch == '*':
                res = res[:-1]
            elif ch == '#':
                res = res + res
            elif ch == '%':
                res = res[::-1]
            else:
                res += ch
        return res

