var processStr = function(s) {
    let res = '';
    for (const ch of s) {
        if (ch === '*') {
            res = res.slice(0, -1);
        } else if (ch === '#') {
            res = res + res;
        } else if (ch === '%') {
            res = res.split('').reverse().join('');
        } else {
            res += ch;
        }
    }
    return res;
};
